// Iterative factorial — accumulator loop.
int factorial(int n) {
    int result = 1;
    int i = 1;
    while (i <= n) {
        result = result * i;
        i = i + 1;
    }
    return result;
}

// Iterative Fibonacci — two-accumulator update.
int fib_iter(int n) {
    int a = 0;
    int b = 1;
    int i = 0;
    while (i < n) {
        int next = a + b;
        a = b;
        b = next;
        i = i + 1;
    }
    return a;
}

// Euclidean GCD — iterative, integer-only.
int gcd(int a, int b) {
    while (b != 0) {
        int t = b;
        b = a % b;
        a = t;
    }
    return a;
}

// Trial-division primality test.
bool is_prime(int n) {
    if (n < 2) {
        return false;
    }
    int i = 2;
    while (i * i <= n) {
        if (n % i == 0) {
            return false;
        }
        i = i + 1;
    }
    return true;
}

